import { useState, useRef, useEffect } from "react";
import API from "../services/api";
import "./ProfileModal.css";

export default function ProfileModal({ currentUser, onClose, onProfileUpdate }) {
  const [tab, setTab] = useState("profile");
  const [bio, setBio] = useState(currentUser?.bio || "");
  const [profilePic, setProfilePic] = useState(currentUser?.profilePic || "");
  const [isPrivate, setIsPrivate] = useState(currentUser?.isPrivate || false);
  const [settings, setSettings] = useState(currentUser?.settings || { showOnlineStatus: true, showReadReceipts: true, showLastSeen: true });
  const [followers, setFollowers] = useState([]);
  const [following, setFollowing] = useState([]);
  const [requests, setRequests] = useState([]);
  const [saving, setSaving] = useState(false);
  const [uploading, setUploading] = useState(false);
  const fileRef = useRef();

  useEffect(() => { fetchData(); }, []);

  const fetchData = async () => {
    try {
      const res = await API.get(`/users/${currentUser.username}`);
      setFollowers(res.data.followers || []);
      setFollowing(res.data.following || []);
      setRequests(res.data.followRequests || []);
      setProfilePic(res.data.profilePic || "");
      setBio(res.data.bio || "");
      setIsPrivate(res.data.isPrivate || false);
      setSettings(res.data.settings || { showOnlineStatus: true, showReadReceipts: true, showLastSeen: true });
    } catch (err) { console.log(err); }
  };

  const handlePicUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    setUploading(true);
    const fd = new FormData();
    fd.append("profilePic", file);
    try {
      const res = await API.post("/users/me/pic", fd);
      setProfilePic(res.data.profilePic);
      onProfileUpdate && onProfileUpdate({ ...currentUser, profilePic: res.data.profilePic });
    } catch (err) { console.log(err); }
    setUploading(false);
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      await API.put("/users/me/profile", { bio, isPrivate });
      onProfileUpdate && onProfileUpdate({ ...currentUser, bio, isPrivate });
    } catch (err) { console.log(err); }
    setSaving(false);
  };

  const handleSettingToggle = async (key) => {
    const newVal = !settings[key];
    const newSettings = { ...settings, [key]: newVal };
    setSettings(newSettings);
    try {
      await API.put("/users/me/settings", { [key]: newVal });
      onProfileUpdate && onProfileUpdate({ ...currentUser, settings: newSettings });
    } catch (err) { console.log(err); }
  };

  const handleAccept = async (username) => {
    try {
      await API.post(`/users/${username}/accept`);
      setRequests(r => r.filter(u => u.username !== username));
      fetchData();
    } catch (err) { console.log(err); }
  };

  const handleDecline = async (username) => {
    try {
      await API.post(`/users/${username}/decline`);
      setRequests(r => r.filter(u => u.username !== username));
    } catch (err) { console.log(err); }
  };

  const tabs = [
    { id: "profile", label: "Profile" },
    { id: "requests", label: `Requests${requests.length > 0 ? ` (${requests.length})` : ""}` },
    { id: "followers", label: "Followers" },
    { id: "following", label: "Following" },
    { id: "settings", label: "Settings" },
  ];

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="pm-modal" onClick={e => e.stopPropagation()}>
        <button className="pm-close" onClick={onClose}>✕</button>

        {/* Top */}
        <div className="pm-top">
          <div className="pm-avatar-wrap" onClick={() => fileRef.current.click()}>
            {profilePic
              ? <img src={profilePic} alt="" className="pm-avatar-img" />
              : <div className="pm-avatar-letter">{currentUser?.username?.[0]?.toUpperCase()}</div>
            }
            <div className="pm-avatar-hover">{uploading ? "⏳" : "📷"}</div>
          </div>
          <input ref={fileRef} type="file" accept="image/*" hidden onChange={handlePicUpload} />
          <h2 className="pm-uname">@{currentUser?.username}</h2>
          <div className="pm-privacy-badge">{isPrivate ? "🔒 Private" : "🌐 Public"}</div>
          <div className="pm-stats">
            <div className="pm-stat" onClick={() => setTab("followers")}>
              <span className="pm-stat-n">{followers.length}</span>
              <span className="pm-stat-l">Followers</span>
            </div>
            <div className="pm-divider" />
            <div className="pm-stat" onClick={() => setTab("following")}>
              <span className="pm-stat-n">{following.length}</span>
              <span className="pm-stat-l">Following</span>
            </div>
            {requests.length > 0 && <>
              <div className="pm-divider" />
              <div className="pm-stat" onClick={() => setTab("requests")}>
                <span className="pm-stat-n" style={{color:"var(--accent)"}}>{requests.length}</span>
                <span className="pm-stat-l">Requests</span>
              </div>
            </>}
          </div>
        </div>

        {/* Tabs */}
        <div className="pm-tabs">
          {tabs.map(t => (
            <button key={t.id} className={`pm-tab ${tab===t.id?"active":""}`} onClick={() => setTab(t.id)}>
              {t.label}
            </button>
          ))}
        </div>

        <div className="pm-body">
          {/* Profile tab */}
          {tab === "profile" && (
            <div className="pm-profile-tab">
              <label className="pm-label">BIO</label>
              <textarea className="pm-bio" placeholder="Write something about yourself..."
                value={bio} onChange={e => setBio(e.target.value)} maxLength={150} />
              <span className="pm-count">{bio.length}/150</span>

              <label className="pm-label" style={{marginTop:"12px"}}>ACCOUNT TYPE</label>
              <div className="pm-toggle-row">
                <div>
                  <div className="pm-toggle-title">{isPrivate ? "🔒 Private Account" : "🌐 Public Account"}</div>
                  <div className="pm-toggle-sub">{isPrivate ? "Only approved followers can see your content" : "Anyone can follow and message you"}</div>
                </div>
                <button className={`toggle-btn ${isPrivate ? "on" : ""}`} onClick={() => setIsPrivate(!isPrivate)}>
                  <span className="toggle-thumb" />
                </button>
              </div>

              <button className="pm-save" onClick={handleSave} disabled={saving}>
                {saving ? "Saving..." : "Save Changes"}
              </button>
            </div>
          )}

          {/* Follow requests */}
          {tab === "requests" && (
            <div className="pm-user-list">
              {requests.length === 0
                ? <p className="pm-empty">No pending requests</p>
                : requests.map(u => (
                  <div key={u._id} className="pm-request-row">
                    <div className="pm-user-av">
                      {u.profilePic ? <img src={u.profilePic} alt="" /> : u.username?.[0]?.toUpperCase()}
                    </div>
                    <span className="pm-user-name">@{u.username}</span>
                    <div className="pm-request-btns">
                      <button className="accept-btn" onClick={() => handleAccept(u.username)}>✓</button>
                      <button className="decline-btn" onClick={() => handleDecline(u.username)}>✕</button>
                    </div>
                  </div>
                ))
              }
            </div>
          )}

          {/* Followers / Following */}
          {(tab === "followers" || tab === "following") && (
            <div className="pm-user-list">
              {(tab==="followers" ? followers : following).length === 0
                ? <p className="pm-empty">{tab==="followers" ? "No followers yet" : "Not following anyone"}</p>
                : (tab==="followers" ? followers : following).map(u => (
                  <div key={u._id} className="pm-user-row">
                    <div className="pm-user-av">
                      {u.profilePic ? <img src={u.profilePic} alt="" /> : u.username?.[0]?.toUpperCase()}
                    </div>
                    <span className="pm-user-name">@{u.username}</span>
                  </div>
                ))
              }
            </div>
          )}

          {/* Settings */}
          {tab === "settings" && (
            <div className="pm-settings">
              <label className="pm-label">PRIVACY</label>
              {[
                { key: "showOnlineStatus", label: "Show Online Status", sub: "Let others see when you're active" },
                { key: "showReadReceipts", label: "Blue Ticks (Read Receipts)", sub: "Show when you've read messages" },
                { key: "showLastSeen", label: "Show Last Seen", sub: "Let others see when you were last active" },
              ].map(s => (
                <div key={s.key} className="pm-toggle-row">
                  <div>
                    <div className="pm-toggle-title">{s.label}</div>
                    <div className="pm-toggle-sub">{s.sub}</div>
                  </div>
                  <button className={`toggle-btn ${settings[s.key] ? "on" : ""}`} onClick={() => handleSettingToggle(s.key)}>
                    <span className="toggle-thumb" />
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
